import 'dart:convert';
import 'dart:typed_data';

class LeicaBadgePng {
  const LeicaBadgePng._();

  static Uint8List bytesForSize(int size) {
    return base64Decode(switch (size) {
      48 => _logo48,
      72 => _logo72,
      _ => _logo72,
    });
  }

  static const _logo48 =
      '';

  static const _logo72 =
      '';
}
